import timeimport numpy as npimport urdfpyimport trimesh# Load URDFrobot = urdfpy.URDF.load("/Users/biswargabidittamuli/InsectsCADModels/SeparatedInsects/AnoplophoraMalaciaca/am.urdf")print("Model loaded successfully")print("Number of links:", len(robot.links))print("Number of joints:", len(robot.joints))# ── Animation parameters ──────────────────────────────────────────FREQ        = 2.0DURATION    = 5.0FPS         = 60N_FRAMES    = int(DURATION * FPS)PITCH_AMP   = np.deg2rad(-30)ROLL_AMP    = np.deg2rad(5)YAW_AMP     = np.deg2rad(-5)ROLL_PHASE  = np.pi / 2YAW_PHASE   = np.pi / 4t   = np.linspace(0, DURATION, N_FRAMES)phi = 2 * np.pi * FREQ * tcfg_trajectory = {    "l_w_pitch_joint" :  PITCH_AMP * (1 - np.sin(phi)) / 2,    "l_w_roll_joint"  :  ROLL_AMP  * (1-np.sin(phi + ROLL_PHASE))/2,    "l_w_yaw_joint"   :  YAW_AMP   * (1-np.sin(phi + YAW_PHASE))/2,    "r_w_pitch_joint" :  PITCH_AMP * (1 - np.sin(phi)) / 2,    "r_w_roll_joint"  : -ROLL_AMP  * (1-np.sin(phi + ROLL_PHASE))/2,    "r_w_yaw_joint"   : -YAW_AMP   * (1-np.sin(phi + YAW_PHASE))/2,}# ── joint_names defined HERE before any function uses it ──────────joint_names = list(cfg_trajectory.keys())print(f"\nAnimating {N_FRAMES} frames at {FPS} FPS over {DURATION}s ...")print(f"Flapping frequency: {FREQ} Hz | Pitch ±{np.rad2deg(PITCH_AMP):.0f}° | Roll ±{np.rad2deg(ROLL_AMP):.0f}° | Yaw ±{np.rad2deg(YAW_AMP):.0f}°")# ── Helper function ───────────────────────────────────────────────def get_cfg_at_frame(i):    return {name: float(cfg_trajectory[name][i]) for name in joint_names}# ── Build initial scene at frame 0 ────────────────────────────────cfg0 = get_cfg_at_frame(0)fk0  = robot.visual_trimesh_fk(cfg=cfg0)scene      = trimesh.Scene()geom_names = []for mesh, tf in fk0.items():    name = str(id(mesh))    scene.add_geometry(mesh, transform=tf, geom_name=name)    geom_names.append((mesh, name))# ── Callback: update transforms each frame ────────────────────────frame_index = [0]def animate_callback(scene):    i   = frame_index[0]    cfg = get_cfg_at_frame(i)    fk  = robot.visual_trimesh_fk(cfg=cfg)    for (mesh, name), (_, tf) in zip(geom_names, fk.items()):        scene.graph.update(name, matrix=tf)    frame_index[0] = (i + 1) % N_FRAMES# ── Launch viewer ─────────────────────────────────────────────────print("Opening viewer window ...")start = time.time()scene.show(    callback        = animate_callback,    callback_period = 1.0 / FPS)end = time.time()print(f"\nAnimation finished in {end - start:.2f} seconds")